query:
{
  vms(
    where: {
      OR: [
        { cyscaleOSIsOutdated: { eq: true } }
        { imageName_MATCHES: "(?i).*(ubuntu.*(18[._-]?04|20[._-]?04|bionic|focal)|centos.*7|rhel.*7|red hat.*7|debian.*(10|11)|buster|bullseye|amazon linux 2|amzn2|amazon linux ami|windows.*server.*2012|windows.*server.*2016).*" }
        { osImage_MATCHES: "(?i).*(ubuntu.*(18[._-]?04|20[._-]?04|bionic|focal)|centos.*7|rhel.*7|red hat.*7|debian.*(10|11)|buster|bullseye|windows.*server.*2012|windows.*server.*2016).*" }
        { osNameEn_MATCHES: "(?i).*(ubuntu.*(18[._-]?04|20[._-]?04|bionic|focal)|centos.*7|rhel.*7|red hat.*7|debian.*(10|11)|buster|bullseye|amazon linux 2|windows.*server.*2012|windows.*server.*2016).*" }
        { storageProfileImageReferencePublisher_MATCHES: "(?i).*canonical.*", storageProfileImageReferenceSku_MATCHES: "(?i).*(18[_-]?04|20[_-]?04|bionic|focal).*" }
        { storageProfileImageReferencePublisher_MATCHES: "(?i).*microsoftwindowsserver.*", storageProfileImageReferenceSku_MATCHES: "(?i).*(2012|2016).*" }
      ]
    }
  ) {
    ...AssetFragment
    cyscaleOSIsOutdated
    osType
    imageName
    platformName
    platformVersion
    osImage
    osName
    osNameEn
    osVersion
    imageId
    storageProfileImageReferencePublisher
    storageProfileImageReferenceOffer
    storageProfileImageReferenceSku
    storageProfileImageReferenceVersion
    storageProfileImageReferenceExactVersion
  }
}
